UPDATE TB_WB21M01
SET    WBS_REMARK = #{remarks, jdbcType=VARCHAR}
	 , UDT_ID   = #{userId}
	 , UDT_PGM  = #{pgmId}
	 , UDT_DTTM = SYSDATE
WHERE  FILE_TRGT_KEY = #{sjFileTrgtKey}

		UPDATE TB_WB22D02
		SET
			  DESIGN_MNG = #{designMng, jdbcType=VARCHAR}
			, DELIVER_DAY = TO_DATE(NULLIF(TRIM(#{deliverDay, jdbcType=VARCHAR}), ''), 'YYYY-MM-DD')
			, MODEL_CLNT_NM = #{modelClntNm, jdbcType=VARCHAR}
			, MODEL_COMP_DT = TO_DATE(NULLIF(TRIM(#{modelCompDt, jdbcType=VARCHAR}), ''), 'YYYY-MM-DD')
			, OUT_CLNT_NM = #{outClntNm, jdbcType=VARCHAR}
			, OUT_COMP_DT = TO_DATE(NULLIF(TRIM(#{outCompDt, jdbcType=VARCHAR}), ''), 'YYYY-MM-DD')
			, CAM_CLNT_NM = #{camClntNm, jdbcType=VARCHAR}
			, CAM_COMP_DT = TO_DATE(NULLIF(TRIM(#{camCompDt, jdbcType=VARCHAR}), ''), 'YYYY-MM-DD')
			, MACHIN_MNG_NM = #{machinMngNm, jdbcType=VARCHAR}
			, MM_MEMO = #{mmMemo, jdbcType=VARCHAR}
			, DWG_MEMO = #{dwgMemo, jdbcType=VARCHAR}
			, PRD_MEMO = #{prdMemo, jdbcType=VARCHAR}
			, SALES_MEMO = #{salesMemo, jdbcType=VARCHAR}
			, PM_MEMO = #{pmMemo, jdbcType=VARCHAR}
			, REMARK = #{remark, jdbcType=VARCHAR}
			, UDT_ID = #{userId}
			, UDT_PGM = #{pgmId}
			, UDT_DTTM = SYSDATE
		WHERE CO_CD = #{coCd}
		  AND SALES_CD = #{salesCd}
  		  -- 아래는 동시성(Optimistic Lock) 체크 목적이라면 문자열 비교 대신 "타입"으로 비교 권고
		  AND ( #{udtDttm} IS NULL OR UDT_DTTM = TO_TIMESTAMP(#{udtDttm}, 'YYYY-MM-DD HH24:MI:SS') )

