UPDATE TB_WB22M01
SET    VER_NO = TO_CHAR(TO_NUMBER(NVL(VER_NO, '0')) + 1)
	 , UDT_ID = #{userId}
	 , UDT_PGM = #{pgmId}
	 , UDT_DTTM = SYSDATE
WHERE  CO_CD = #{coCd}
  AND  SALES_CD = #{salesCd}

UPDATE TB_WB22M01
SET    WBS_PLANS_DT = TO_DATE(#{wbsPlansDtFm}, 'YYYY-MM-DD')
	 , WBS_PLANE_DT = TO_DATE(#{wbsPlaneDtFm}, 'YYYY-MM-DD')
	 , UDT_ID = #{userId}
	 , UDT_PGM = #{pgmId}
	 , UDT_DTTM = SYSDATE
WHERE  FILE_TRGT_KEY = #{fileTrgtKey}

UPDATE TB_WB22M01
SET    WBS_PLANS_DT = TO_DATE(#{wbsPlansDtFm}, 'YYYY-MM-DD')
	 , WBS_PLANE_DT = TO_DATE(#{wbsPlaneDtFm}, 'YYYY-MM-DD')
	 , UDT_ID = #{userId}
	 , UDT_PGM = #{pgmId}
	 , UDT_DTTM = SYSDATE
WHERE  CO_CD = #{coCd}
  AND  SALES_CD = #{salesCd}
  AND  WBS_PLAN_CODE_ID = #{wbsPlanCodeId}
  AND  WBS_PLAN_CODE_KIND = 'WBSCODE'

UPDATE TB_WB22M01
SET    REVISED_FINISH_DT 		= #{revisedFinishDt}
	 , WBS_PLAN_STS_CODE_ID     = #{wbsPlanStsCodeId}
	 , CLOSE_YN = #{planCloseYn}
	 , UDT_ID   = #{userId}
	 , UDT_PGM  = #{pgmId}
	 , UDT_DTTM = SYSDATE
WHERE  CO_CD = #{coCd}
  AND  SALES_CD = #{salesCd}
  AND  WBS_PLAN_CODE_KIND = #{wbsPlanCodeKind}
  AND  (REVISED_FINISH_DT   != #{revisedFinishDt}
   OR  WBS_PLAN_STS_CODE_ID != #{wbsPlanStsCodeId})

